#include <Wire.h>
#include <SPI.h>
#include <SD.h>
extern int pid_heater_control(float,float,float,float,float,float,float*,float*);
extern void adaptive_pid_gain_schedule(float,float*,float*,float*);
volatile long encCount=0;
void hall_isr(){encCount++;}
void hall_setup(){attachInterrupt(digitalPinToInterrupt(2),hall_isr,RISING);}
float hall_rpm(float dt){long c=encCount;encCount=0;return(c/20.0f)*(60.0f/dt);}
void motor_setup(){pinMode(9,OUTPUT);}
void motor_set(int v){analogWrite(9,constrain(v,0,255));}
File lf;
void log_setup(){if(SD.begin(10))lf=SD.open("m.csv",FILE_WRITE);}
void log_write(unsigned long t,float sp,float pv,int pw){
  if(!lf)return;
  lf.print(t);lf.print(',');lf.print(sp,1);lf.print(',');lf.print(pv,1);lf.print(',');lf.println(pw);}
void oled_show(float sp,float pv,int pw){(void)sp;(void)pv;(void)pw;}
void fault_check(float rpm){
  if(rpm<0.0f||rpm>3500.0f){motor_set(0);Serial.println("FAULT:RPM");while(1);}}
static float ig=0,le=0;
float SP=1500.0f;
unsigned long pt=0;
void setup(){
  Serial.begin(115200);
  hall_setup();motor_setup();log_setup();}
void loop(){
  unsigned long n=millis();
  float dt=(n-pt)/1000.0f;
  if(dt<0.05f)return;
  pt=n;
  float rpm=hall_rpm(dt);
  fault_check(rpm);
  float kp,ki,kd;
  adaptive_pid_gain_schedule(SP-rpm,&kp,&ki,&kd);
  int pw=pid_heater_control(SP,rpm,dt,kp,ki,kd,&ig,&le);
  motor_set(pw);
  oled_show(SP,rpm,pw);
  log_write(n,SP,rpm,pw);}
